#!/usr/bin/env node
const { spawn, spawnSync } = require('child_process')
const fs = require('fs')
const path = require('path')

try {
  process.env = require('../../env.json')
} catch {
  process.env = { PORT: '8080' }
}

const {
  BITCOIN_RPCUSER,
  BITCOIN_RPCPASSWORD,
  BITCOIN_RPCPORT,
  BITCOIN_CLI_BIN, 
  LIGHTNING_DIR_4,
  LIGHTNING_DIR_5,
  LIGHTNING_DIR_6,
  LIGHTNINGD_BIN,
  LIGHTNING_CLI_BIN
} = process.env

const LIGHTNING_BIN = LIGHTNINGD_BIN || '/usr/local/bin/lightningd'
const LIGHTNING_CLI = LIGHTNING_CLI_BIN || '/usr/local/bin/lightning-cli' 
const BITCOIN_CLI = BITCOIN_CLI_BIN || '/usr/local/bin/bitcoin-cli' 

const LIGHTNING_DIRS = [
  LIGHTNING_DIR_4 || '/Users/a1707/lightning4',
  LIGHTNING_DIR_5 || '/Users/a1707/lightning5',
  LIGHTNING_DIR_6 || '/Users/a1707/lightning6'
]
const LIGHTNING_PORTS = [9740, 9741, 9742]

const sleep = (ms) => new Promise(r => setTimeout(r, ms))
const log = console.log

async function waitForRPC(dir, timeout = 15000) {
  log(`Waiting for RPC to be ready at ${dir}...`);
  const start = Date.now()
  let attempts = 0;

  while (Date.now() - start < timeout) {
    const res = spawnSync(LIGHTNING_CLI, [
      `--lightning-dir=${dir}`,
      '--network=regtest',
      'getinfo'
    ]);

    if (res.status === 0) {
      log(`RPC check successful for ${dir}.`);
      return true;
    }

    await sleep(500);
    attempts++;

    if (attempts <= 3) {
      log(`... RPC check attempt ${attempts} for ${dir} failed ...`);
      const errorMsg = res.stderr ? res.stderr.toString().trim() : 'No stderr output';
      if (errorMsg) {
          log(`Error: ${errorMsg}`);
      }
      if (res.error && res.error.code === 'ENOENT') {
          log(`(Could not find executable: ${LIGHTNING_CLI}. Check your LIGHTNING_CLI_BIN in env.json)`);
      }
    }
  }
  log(`RPC check timed out for ${dir}.`);
  return false;
}

module.exports = {
  async start() {
    log('=== Starting Lightning nodes (node4–node6) ===')
    LIGHTNING_DIRS.forEach(dir => {
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true })
    })

    for (let i = 0; i < LIGHTNING_DIRS.length; i++) {
      const dir = LIGHTNING_DIRS[i]
      const port = LIGHTNING_PORTS[i]
      log(`→ Starting lightningd for ${dir} on port ${port}`)
      
      const args = [
        '--network=regtest',
        `--lightning-dir=${dir}`,
        `--bitcoin-rpcuser=${BITCOIN_RPCUSER}`,
        `--bitcoin-rpcpassword=${BITCOIN_RPCPASSWORD}`,
        '--bitcoin-rpcconnect=127.0.0.1',
        `--bitcoin-rpcport=${BITCOIN_RPCPORT}`,
        `--bitcoin-cli=${BITCOIN_CLI}`,
        `--addr=127.0.0.1:${port}`,
        `--log-file=${dir}/debug.log`,
        '--daemon',
        '--disable-plugin=clnrest',
        '--disable-plugin=wss-proxy'
      ]
      
      const child = spawn(LIGHTNING_BIN, args, { 
        detached: true, 
        stdio: 'pipe', 
        env: process.env 
      })

      child.stderr.on('data', (data) => {
        console.error(`[FATAL ERROR lightningd ${dir}]: ${data.toString()}`);
      });
      child.on('exit', (code) => {
        if (code !== 0) {
            log(`lightningd process for ${dir} exited with code ${code}`);
        }
      });

      child.unref()
      
      const rpcReady = await waitForRPC(dir, 15000) 
      
      if (rpcReady) log(`✅ Lightning node ready: ${dir}`)
      else {
          log(`⚠️ Lightning node failed to start RPC: ${dir}`);
          log(`Check the log file for errors: cat ${dir}/debug.log`);
      }
    }
    log('All Lightning nodes startup process complete.')
  },

  async stop() {
    log('Stopping lightningd (best effort)...')
    try {
      const running = spawnSync('pgrep', ['-x', 'lightningd'])
      if (running.status === 0) {
        spawnSync('pkill', ['-f', 'lightningd'])
        log('✅ lightningd stopped.')
      } else {
        log('No lightningd processes found.')
      }
    } catch (err) {
      log('⚠️ Error stopping lightningd:', err.message)
    }
  }
}